{
  "name": "NovaMarket AI",
  "description": "A cutting-edge e-commerce platform featuring a personalized AI shopping assistant powered by Gemini to help you find the perfect products."
}

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: 'Electronics' | 'Lifestyle' | 'Fashion' | 'Home';
  image: string;
  rating: number;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export type Page = 'home' | 'products' | 'cart';

import { GoogleGenAI, Type } from "@google/genai";
import { Product } from "../types";
import { PRODUCTS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getShoppingAssistantResponse = async (userQuery: string, cartItems: string[]) => {
  const model = "gemini-3-flash-preview";

  // Format product list for the model
  const productContext = PRODUCTS.map(p => 
    `ID: ${p.id}, Name: ${p.name}, Category: ${p.category}, Price: $${p.price}, Description: ${p.description}`
  ).join("\n");

  const systemInstruction = `
    You are NovaMarket's AI Shopping Assistant. 
    Your goal is to help users find the best products from our catalog.

    Current Catalog:
    ${productContext}

    User's Current Cart IDs: [${cartItems.join(", ")}]

    Response Requirements:
    1. Be friendly and professional.
    2. If the user asks for a recommendation, suggest 1-3 specific products from our catalog by name.
    3. Always explain why you recommended those specific items based on their features.
    4. Format your response in a helpful way.
    5. If the user is asking about things we don't have, politely mention you're limited to our current catalog but can suggest the closest alternatives.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: userQuery,
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text || "I'm sorry, I couldn't process that request right now.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I am having some trouble connecting to my brain. Please try again later!";
  }
};

import React from 'react';
import { Page } from '../types';

interface NavbarProps {
  currentPage: Page;
  setCurrentPage: (page: Page) => void;
  cartCount: number;
}

