    <nav className="sticky top-0 z-40 w-full border-b border-slate-200 glass px-4 py-3 sm:px-8">
      <div className="max-w-7xl mx-auto flex items-center justify-between">
        <div 
          className="flex items-center gap-2 cursor-pointer group"
          onClick={() => setCurrentPage('home')}
        >
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl group-hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-200">
            N
          </div>
          <span className="text-xl font-bold tracking-tight text-slate-800 hidden sm:block">NovaMarket</span>
        </div>

        <div className="flex items-center gap-6 sm:gap-10">
          <button 
            onClick={() => setCurrentPage('products')}
            className={`text-sm font-medium transition-colors ${currentPage === 'products' ? 'text-indigo-600' : 'text-slate-500 hover:text-indigo-600'}`}
          >
            Shop
          </button>

          <button 
            onClick={() => setCurrentPage('cart')}
            className="relative p-2 text-slate-500 hover:text-indigo-600 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><path d="M3 6h18"/><path d="M16 10a4 4 0 0 1-8 0"/></svg>
            {cartCount > 0 && (
              <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-indigo-600 text-[10px] font-bold text-white ring-2 ring-white">
