              <div className="absolute inset-0 flex flex-col items-start justify-center text-left p-12 sm:p-20 bg-gradient-to-r from-slate-900/90 via-slate-900/40 to-transparent">
                <span className="inline-block bg-indigo-600 text-white text-[10px] font-bold px-3 py-1 rounded-full uppercase tracking-widest mb-4">Summer 2024 Collection</span>
                <h1 className="text-5xl sm:text-7xl font-extrabold text-white mb-6 leading-[1.1] tracking-tight max-w-2xl">
