import { GoogleGenAI, Type } from "@google/genai";
import { Product } from "../types";
import { PRODUCTS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getShoppingAssistantResponse = async (userQuery: string, cartItems: string[]) => {
  const model = "gemini-3-flash-preview";

  // Format product list for the model
  const productContext = PRODUCTS.map(p => 
    `ID: ${p.id}, Name: ${p.name}, Category: ${p.category}, Price: $${p.price}, Description: ${p.description}`
  ).join("\n");

  const systemInstruction = `
    You are the Personal AI Assistant for Susan's Online Shopping Platform. 
    Our catalog includes high-quality Shoes, Electronics, Accessories, Fashion, and Home items.

    Current Catalog:
    ${productContext}

    User's Current Cart IDs: [${cartItems.join(", ")}]

    Response Requirements:
    1. Be friendly, professional, and helpful. Mention you are Susan's Shopping Assistant.
    2. Suggest 1-3 specific products from our catalog if the user asks for recommendations.
    3. We accept M-Pesa, PayPal, and Visa/Mastercard. If the user asks about payments, explain our diverse options.
    4. Format your response clearly.
    5. If an item isn't in our catalog, suggest the closest match from our Shoes, Electronics, or Accessories departments.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: userQuery,
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text || "I'm sorry, I couldn't process that request right now.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I am having some trouble connecting to my brain. Please try again later!";
  }
};

