import { Assistant } from './components/Assistant';
import { Login } from './components/Login';
import { Contact } from './components/Contact';
import { backend } from './services/backendService';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('mpesa');
  const [checkoutStatus, setCheckoutStatus] = useState<'idle' | 'loading' | 'success'>('idle');

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchTerm, products]);

  const featuredProducts = useMemo(() => products.filter(p => p.featured), [products]);

  const toggleFeatured = (id: string) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, featured: !p.featured } : p));
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => setCart(prev => prev.filter(item => item.id !== id));

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleCheckout = async () => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    setCheckoutStatus('loading');
    await backend.placeOrder(user.id, cart, totalCartPrice, paymentMethod);
    setCheckoutStatus('success');
    setTimeout(() => {
      setCart([]);
      setCheckoutStatus('idle');
      setCurrentPage('home');
    }, 2500);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
  };

  const totalCartPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartItemIds = cart.map(item => item.id);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Navbar 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage} 
        cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
        user={user}
        onLogout={handleLogout}
      />

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8 sm:px-8">
        {currentPage === 'login' && <Login onLogin={(u) => { setUser(u); setCurrentPage('home'); }} onBack={() => setCurrentPage('home')} />}
        {currentPage === 'contact' && <Contact />}

        {currentPage === 'home' && (
          <div className="space-y-16 py-8 animate-in fade-in duration-500">
            {/* Hero */}
            <section className="relative h-[450px] sm:h-[600px] rounded-[3rem] overflow-hidden bg-indigo-950 group shadow-2xl border-4 border-white">
              <img 
                src="https://images.unsplash.com/photo-1441986300917-64674bd600d8?auto=format&fit=crop&q=80&w=1600" 
                alt="Hero" 
                className="absolute inset-0 w-full h-full object-cover opacity-50 group-hover:scale-105 transition-transform duration-1000"
              />
              <div className="absolute inset-0 flex flex-col items-start justify-center text-left p-12 sm:p-24 bg-gradient-to-r from-indigo-950/90 via-indigo-950/40 to-transparent">
                <span className="inline-block bg-white text-indigo-950 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.2em] mb-6 shadow-xl">Susan's Premium Market</span>
                <h1 className="text-6xl sm:text-8xl font-black text-white mb-6 leading-[1] tracking-tighter max-w-2xl">
                  Built For <span className="text-indigo-400">Kenya</span>.
                </h1>
                <p className="text-xl sm:text-2xl text-slate-300 max-w-lg mb-12 leading-relaxed font-bold">Safari boots, the latest smartphones, and accessories—all delivered with AI smarts.</p>
                <div className="flex flex-col sm:flex-row gap-6">
                  <button onClick={() => setCurrentPage('products')} className="bg-white text-indigo-950 px-12 py-5 rounded-2xl font-black text-xl hover:bg-indigo-50 transition-all shadow-2xl active:scale-95">Shop Catalog</button>
                  <button onClick={() => setCurrentPage('contact')} className="glass text-white px-12 py-5 rounded-2xl font-black text-xl border-2 border-white/20 hover:bg-white/10 transition-all">Contact Us</button>
                </div>
              </div>
            </section>

            {/* Featured */}
            <section>
              <div className="flex items-end justify-between mb-12">
                <div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Bestsellers in Nairobi</h2>
                  <p className="text-slate-500 mt-2 font-bold text-lg">Curated essentials for the modern Kenyan lifestyle.</p>
                </div>
                <button onClick={() => setCurrentPage('products')} className="text-indigo-600 font-black hover:underline">Explore More</button>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                {featuredProducts.map(p => (
                  <ProductCard key={p.id} product={p} onAdd={() => addToCart(p)} isAdmin={user?.isAdmin} onToggleFeatured={() => toggleFeatured(p.id)} />
                ))}
              </div>
            </section>
          </div>
        )}

        {currentPage === 'products' && (
          <div className="space-y-12 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-8">
              <div>
                <h1 className="text-5xl font-black text-slate-900 tracking-tighter">Marketplace</h1>
                <p className="text-slate-500 mt-2 font-bold text-lg">Quality tech and fashion, sourced for you.</p>
              </div>
              <div className="flex flex-col sm:flex-row gap-4 items-center w-full md:w-auto">
                <div className="relative w-full sm:w-80">
                  <input 
                    type="text" placeholder="Search brands..." 
                    className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-slate-100 focus:border-indigo-600 outline-none transition-all shadow-sm font-bold"
                    value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}
                  />
                  <svg className="absolute left-4 top-4 text-slate-400" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 sm:pb-0 w-full scrollbar-hide">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat} onClick={() => setSelectedCategory(cat)}
                      className={`whitespace-nowrap px-6 py-3.5 rounded-2xl text-sm font-black transition-all ${selectedCategory === cat ? 'bg-indigo-600 text-white shadow-xl' : 'bg-white text-slate-600 border-2 border-slate-100 hover:border-indigo-300'}`}
                    >
