              </div>
            ) : (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                <div className="lg:col-span-2 space-y-6">
                  {cart.map(item => (
                    <div key={item.id} className="bg-white p-6 rounded-[2.5rem] border-2 border-slate-50 flex gap-8 shadow-sm hover:shadow-xl transition-all">
                      <img src={item.image} alt={item.name} className="w-36 h-36 rounded-3xl object-cover shadow-lg" />
                      <div className="flex-1 flex flex-col justify-between">
                        <div className="flex justify-between items-start">
                          <div>
                            <h3 className="text-2xl font-black text-slate-900 leading-tight">{item.name}</h3>
                            <span className="text-xs font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-widest">{item.category}</span>
                          </div>
                          <button onClick={() => removeFromCart(item.id)} className="p-3 text-slate-300 hover:text-red-500 bg-slate-50 rounded-2xl transition-all">
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
                          </button>
                        </div>
                        <div className="flex justify-between items-center mt-6">
                          <div className="flex items-center gap-6 bg-slate-50 rounded-2xl p-1.5 border border-slate-100">
                            <button onClick={() => updateQuantity(item.id, -1)} className="w-10 h-10 flex items-center justify-center text-slate-500 hover:text-indigo-600 hover:bg-white rounded-xl transition-all">
                              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/></svg>
                            </button>
                            <span className="font-black text-xl text-slate-900">{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} className="w-10 h-10 flex items-center justify-center text-slate-500 hover:text-indigo-600 hover:bg-white rounded-xl transition-all">
                              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                            </button>
                          </div>
                          <span className="text-3xl font-black text-slate-900">KES { (item.price * item.quantity).toLocaleString() }</span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="space-y-6">
                  <div className="bg-white p-10 rounded-[3rem] border-2 border-slate-50 shadow-2xl sticky top-28">
                    <h3 className="text-3xl font-black text-slate-900 mb-10">Checkout</h3>

                    <div className="space-y-4 mb-10">
                      <div className="flex justify-between text-slate-500 font-bold text-lg">
                        <span>Items Subtotal</span>
                        <span>KES {totalCartPrice.toLocaleString()}</span>
                      </div>
                      <div className="flex justify-between text-slate-500 font-bold text-lg">
                        <span>Delivery (KE)</span>
                        <span className="text-emerald-500">Free</span>
                      </div>
                      <div className="border-t-4 border-slate-50 pt-8 flex justify-between font-black text-4xl text-slate-900">
                        <span>Total</span>
                        <span>KES {totalCartPrice.toLocaleString()}</span>
                      </div>
                    </div>

                    <div className="mb-10">
                      <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-6">Payment Method</p>
                      <div className="grid grid-cols-2 gap-4">
                        {(['mpesa', 'visa', 'paypal', 'mastercard'] as PaymentMethod[]).map(method => (
                          <button 
                            key={method} onClick={() => setPaymentMethod(method)}
                            className={`flex items-center justify-center p-5 rounded-2xl border-4 transition-all font-black uppercase text-xs tracking-widest ${paymentMethod === method ? 'border-indigo-600 bg-indigo-50 text-indigo-900' : 'border-slate-50 hover:border-slate-100 text-slate-400'}`}
                          >
                            {method}
                          </button>
                        ))}
                      </div>
                    </div>

                    <button 
                      onClick={handleCheckout}
                      disabled={checkoutStatus !== 'idle'}
                      className="w-full bg-slate-900 text-white py-6 rounded-3xl font-black text-2xl hover:bg-indigo-600 transition-all shadow-2xl disabled:opacity-50"
                    >
                      {checkoutStatus === 'loading' ? 'Processing...' : checkoutStatus === 'success' ? 'Ordered!' : 'Confirm Order'}
                    </button>
                    {checkoutStatus === 'success' && (
                      <p className="text-center text-emerald-600 font-bold mt-4 animate-bounce">Order placed! M-Pesa prompt coming soon...</p>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-slate-100 mt-24 py-24 px-4 sm:px-8">
