          <div className="col-span-1 md:col-span-2">
            <div className="flex items-center gap-3 mb-8">
              <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black text-2xl shadow-xl">S</div>
              <span className="text-3xl font-black tracking-tighter text-slate-900">Susan's Marketplace</span>
            </div>
            <p className="text-slate-500 max-w-sm mb-10 leading-relaxed font-bold text-lg">Delivering the finest Kenyan-sourced fashion, tech, and art with an intelligent personal shopping assistant.</p>
            <div className="flex gap-6">
               <div className="flex items-center gap-4 grayscale opacity-40">
