               </div>
            </div>
          </div>
          <div>
            <h4 className="font-black text-slate-900 mb-8 uppercase text-xs tracking-[0.3em]">Shop KE</h4>
            <ul className="space-y-4 text-lg font-bold text-slate-500">
              <li><button onClick={() => { setCurrentPage('products'); setSelectedCategory('Shoes'); }} className="hover:text-indigo-600 transition-colors">Safari Shoes</button></li>
