import React, { useState, useMemo } from 'react';
import { Product, CartItem, Page, User, PaymentMethod } from './types';
import { PRODUCTS as INITIAL_PRODUCTS, CATEGORIES } from './constants';
import { Navbar } from './components/Navbar';
import { Assistant } from './components/Assistant';
import { Login } from './components/Login';
import { Contact } from './components/Contact';
import { StyleHub } from './components/StyleHub';
import { backend } from './services/backendService';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('mpesa');
  const [checkoutStatus, setCheckoutStatus] = useState<'idle' | 'loading' | 'success'>('idle');

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchTerm, products]);

  const featuredProducts = useMemo(() => products.filter(p => p.featured), [products]);

  const toggleFeatured = (id: string) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, featured: !p.featured } : p));
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => setCart(prev => prev.filter(item => item.id !== id));

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleCheckout = async () => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    setCheckoutStatus('loading');
    await backend.placeOrder(user.id, cart, totalCartPrice, paymentMethod);
    setCheckoutStatus('success');
    setTimeout(() => {
      setCart([]);
      setCheckoutStatus('idle');
      setCurrentPage('home');
    }, 2500);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
  };

  const totalCartPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartItemIds = cart.map(item => item.id);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Navbar 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage} 
        cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
        user={user}
        onLogout={handleLogout}
      />

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8 sm:px-8">
        {currentPage === 'login' && <Login onLogin={(u) => { setUser(u); setCurrentPage('home'); }} onBack={() => setCurrentPage('home')} />}
        {currentPage === 'contact' && <Contact />}
        {currentPage === 'style-hub' && <StyleHub onAddToCart={addToCart} />}

        {currentPage === 'home' && (
          <div className="space-y-16 py-8 animate-in fade-in duration-500">
            {/* Hero */}
            <section className="relative h-[450px] sm:h-[650px] rounded-[3.5rem] overflow-hidden bg-indigo-950 group shadow-2xl border-4 border-white">
              <img 
                src="https://images.unsplash.com/photo-1441986300917-64674bd600d8?auto=format&fit=crop&q=80&w=1600" 
                alt="Hero" 
                className="absolute inset-0 w-full h-full object-cover opacity-40 group-hover:scale-105 transition-transform duration-1000"
              />
              <div className="absolute inset-0 flex flex-col items-start justify-center text-left p-12 sm:p-24 bg-gradient-to-r from-indigo-950/95 via-indigo-950/40 to-transparent">
                <span className="inline-block bg-white text-indigo-950 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.3em] mb-6 shadow-xl">Handpicked For Kenya</span>
                <h1 className="text-6xl sm:text-8xl font-black text-white mb-6 leading-[1] tracking-tighter max-w-2xl">
                  Luxury <span className="text-indigo-400">Simplified</span>.
                </h1>
                <p className="text-xl sm:text-2xl text-slate-300 max-w-lg mb-12 leading-relaxed font-bold italic">Curating Jewelry, Tech, and Fashion—for the bold and the beautiful.</p>
                <div className="flex flex-col sm:flex-row gap-6">
                  <button onClick={() => setCurrentPage('products')} className="bg-white text-indigo-950 px-12 py-5 rounded-2xl font-black text-xl hover:bg-indigo-50 transition-all shadow-2xl active:scale-95">Shop Now</button>
                  <button onClick={() => setCurrentPage('style-hub')} className="glass text-white px-12 py-5 rounded-2xl font-black text-xl border-2 border-white/20 hover:bg-white/10 transition-all">Try AI Stylist</button>
                </div>
              </div>
            </section>

            {/* Featured */}
            <section>
              <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-4">
