import React, { useState } from 'react';
import { User } from '../types';
import { backend } from '../services/backendService';

interface LoginProps {
  onLogin: (user: User) => void;
  onBack: () => void;
}

export const Login: React.FC<LoginProps> = ({ onLogin, onBack }) => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await backend.login(email);
      onLogin(user);
    } catch (err) {
      alert("Login failed. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-center min-h-[70vh] px-4 py-8 sm:py-20 animate-in fade-in zoom-in-95 duration-300">
      <div className="w-full max-w-md bg-white dark:bg-slate-900 rounded-[2.5rem] sm:rounded-[3rem] p-6 sm:p-10 border border-slate-100 dark:border-slate-800 shadow-2xl relative overflow-hidden transition-colors">
        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50 dark:bg-indigo-900/10 rounded-full blur-3xl -mr-16 -mt-16"></div>

        <div className="text-center mb-8 sm:mb-10 relative">
          <div className="w-14 h-14 sm:w-16 sm:h-16 bg-indigo-600 rounded-2xl flex items-center justify-center text-white font-black text-2xl sm:text-3xl mx-auto mb-4 sm:mb-6 shadow-xl shadow-indigo-100 dark:shadow-none">S</div>
          <h2 className="text-2xl sm:text-3xl font-black text-slate-900 dark:text-white tracking-tighter">Welcome Back</h2>
          <p className="text-slate-500 dark:text-slate-400 text-xs sm:text-sm mt-2 sm:mt-3 font-medium">
            Join Susan's Marketplace for a personalized Kenyan shopping experience.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4 sm:space-y-6 relative">
          <div>
            <label className="block text-[10px] sm:text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2">Email Address</label>
            <input 
              type="email" 
              required
              className="w-full px-5 sm:px-6 py-3.5 sm:py-4 rounded-xl sm:rounded-2xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-bold text-sm sm:text-base" 
              placeholder="susan@kenyamarket.co.ke"
              value={email}
              onChange={e => setEmail(e.target.value)}
            />
          </div>
          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-slate-900 dark:bg-indigo-600 text-white py-4 sm:py-5 rounded-xl sm:rounded-2xl font-black text-base sm:text-lg hover:bg-indigo-600 dark:hover:bg-indigo-700 transition-all hover:shadow-xl active:scale-[0.98] disabled:opacity-50"
          >
            {loading ? 'Authenticating...' : 'Sign In Now'}
          </button>
        </form>

        <div className="mt-8 sm:mt-10 text-center">
           <button onClick={onBack} className="text-xs sm:text-sm font-bold text-slate-400 dark:text-slate-500 hover:text-slate-900 dark:hover:text-white transition-colors">Return to Shop</button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
