interface AffiliateProgramProps {
  user: User | null;
  onJoin: () => void;
  onNavigate: (page: any) => void;
}

export const AffiliateProgram: React.FC<AffiliateProgramProps> = ({ user, onJoin, onNavigate }) => {
  const [copySuccess, setCopySuccess] = useState(false);

  const referralLink = user?.affiliateCode 
    ? `https://susans.market/ref=${user.affiliateCode}` 
    : '';

  const copyToClipboard = () => {
    navigator.clipboard.writeText(referralLink);
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  if (!user) {
    return (
      <div className="max-w-4xl mx-auto py-12 px-4 text-center animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="bg-indigo-600 rounded-[3rem] p-12 sm:p-20 text-white shadow-2xl">
          <h1 className="text-4xl sm:text-6xl font-black tracking-tighter mb-6">Earn with Susan</h1>
          <p className="text-xl sm:text-2xl text-indigo-100 font-bold mb-10 max-w-2xl mx-auto leading-relaxed">
            Join our exclusive affiliate network and earn up to 10% commission on every sale you refer.
          </p>
          <button 
            onClick={() => onNavigate('login')}
            className="bg-white text-indigo-600 px-10 py-5 rounded-2xl font-black text-xl hover:bg-indigo-50 transition-all shadow-xl active:scale-95"
          >
            Sign in to Start Earning
          </button>
        </div>
      </div>
    );
  }

  if (!user.isAffiliate) {
