  return (
    <div className="max-w-6xl mx-auto py-12 px-4 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter">Affiliate Dashboard</h1>
          <p className="text-slate-500 dark:text-slate-400 font-bold">Welcome back, {user.name}. Keep growing your network!</p>
