import React, { useState, useMemo, useEffect } from 'react';
import { Product, CartItem, Page, User, PaymentMethod, Theme } from './types';
import { PRODUCTS as INITIAL_PRODUCTS, CATEGORIES } from './constants';
import { Navbar } from './components/Navbar';
import { Assistant } from './components/Assistant';
import { Login } from './components/Login';
import { Contact } from './components/Contact';
import { StyleHub } from './components/StyleHub';
import { ProductDetail } from './components/ProductDetail';
import { AdminPanel } from './components/AdminPanel';
import { AffiliateProgram } from './components/AffiliateProgram';
import { backend } from './services/backendService';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('mpesa');
  const [checkoutStatus, setCheckoutStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [theme, setTheme] = useState<Theme>('light');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchTerm, products]);

  const featuredProducts = useMemo(() => products.filter(p => p.featured), [products]);

  const toggleFeatured = (id: string) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, featured: !p.featured } : p));
  };

  const handleAddProduct = (newProduct: Product) => {
    setProducts(prev => [newProduct, ...prev]);
    setCurrentPage('products');
  };

  const handleJoinAffiliate = () => {
    if (user) {
      setUser({
        ...user,
        isAffiliate: true,
        affiliateCode: 'SUSAN-' + Math.random().toString(36).substr(2, 5).toUpperCase(),
        earnings: 12500, // Starting simulated earnings
        referrals: 12
      });
    }
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => setCart(prev => prev.filter(item => item.id !== id));

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const openProductDetail = (p: Product) => {
    setSelectedProduct(p);
    setCurrentPage('product-detail');
  };

  const handleCheckout = async () => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    setCheckoutStatus('loading');
    await backend.placeOrder(user.id, cart, totalCartPrice, paymentMethod);
    setCheckoutStatus('success');
    setTimeout(() => {
      setCart([]);
      setCheckoutStatus('idle');
      setCurrentPage('home');
    }, 2500);
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
  };

  const handleUpdateProfilePhoto = (photo: string) => {
    if (user) {
      setUser({ ...user, profilePhoto: photo });
    }
  };

  const totalCartPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartItemIds = cart.map(item => item.id);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      <Navbar 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage} 
        cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
        user={user}
        onLogout={handleLogout}
        theme={theme}
        onToggleTheme={() => setTheme(theme === 'light' ? 'dark' : 'light')}
        onUpdateProfilePhoto={handleUpdateProfilePhoto}
      />

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8 sm:px-8">
        {currentPage === 'login' && <Login onLogin={(u) => { setUser(u); setCurrentPage('home'); }} onBack={() => setCurrentPage('home')} />}
        {currentPage === 'contact' && <Contact />}
        {currentPage === 'style-hub' && <StyleHub onAddToCart={addToCart} />}
        {currentPage === 'admin-panel' && <AdminPanel onAddProduct={handleAddProduct} />}
        {currentPage === 'affiliate' && <AffiliateProgram user={user} onJoin={handleJoinAffiliate} onNavigate={setCurrentPage} />}
        {currentPage === 'product-detail' && selectedProduct && (
          <ProductDetail 
            product={selectedProduct} 
            onAddToCart={addToCart} 
            onBack={() => setCurrentPage('products')} 
          />
        )}

        {currentPage === 'home' && (
          <div className="space-y-16 py-8 animate-in fade-in duration-500">
            {/* Hero */}
            <section className="relative h-[450px] sm:h-[650px] rounded-[3.5rem] overflow-hidden bg-indigo-950 group shadow-2xl border-4 border-white dark:border-slate-800">
              <img 
                src="https://images.unsplash.com/photo-1441986300917-64674bd600d8?auto=format&fit=crop&q=80&w=1600" 
                alt="Hero" 
                className="absolute inset-0 w-full h-full object-cover opacity-40 group-hover:scale-105 transition-transform duration-1000"
              />
              <div className="absolute inset-0 flex flex-col items-start justify-center text-left p-12 sm:p-24 bg-gradient-to-r from-indigo-950/95 via-indigo-950/40 to-transparent">
                <span className="inline-block bg-white text-indigo-950 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.3em] mb-6 shadow-xl">Handpicked For Kenya</span>
                <h1 className="text-6xl sm:text-8xl font-black text-white mb-6 leading-[1] tracking-tighter max-w-2xl">
                  Luxury <span className="text-indigo-400">Simplified</span>.
                </h1>
                <p className="text-xl sm:text-2xl text-slate-300 max-w-lg mb-12 leading-relaxed font-bold italic">Curating Jewelry, Tech, and Fashion—for the bold and the beautiful.</p>
                <div className="flex flex-col sm:flex-row gap-6">
                  <button onClick={() => setCurrentPage('products')} className="bg-white text-indigo-950 px-12 py-5 rounded-2xl font-black text-xl hover:bg-indigo-50 transition-all shadow-2xl active:scale-95">Shop Now</button>
                  <button onClick={() => setCurrentPage('style-hub')} className="glass text-white px-12 py-5 rounded-2xl font-black text-xl border-2 border-white/20 hover:bg-white/10 transition-all">Try AI Stylist</button>
                </div>
              </div>
            </section>

            {/* Featured */}
            <section>
              <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-4">
                <div>
                  <h2 className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter">Bestsellers in Nairobi</h2>
                  <p className="text-slate-500 dark:text-slate-400 mt-2 font-bold text-lg">From Jewelry to Hair Care—Susan picks the best.</p>
                </div>
                <button onClick={() => setCurrentPage('products')} className="text-indigo-600 font-black uppercase text-xs tracking-widest hover:underline">Full Catalog →</button>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                {featuredProducts.map(p => (
                  <ProductCard key={p.id} product={p} onAdd={() => addToCart(p)} onClick={() => openProductDetail(p)} isAdmin={user?.isAdmin} onToggleFeatured={() => toggleFeatured(p.id)} />
                ))}
              </div>
            </section>
          </div>
        )}

        {currentPage === 'products' && (
          <div className="space-y-12 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-8">
              <div>
                <h1 className="text-5xl font-black text-slate-900 dark:text-white tracking-tighter">Marketplace</h1>
                <p className="text-slate-500 dark:text-slate-400 mt-2 font-bold text-lg">Explore our diverse departments.</p>
              </div>
              <div className="flex flex-col sm:flex-row gap-4 items-center w-full md:w-auto">
                <div className="relative w-full sm:w-80">
                  <input 
                    type="text" placeholder="Search brands..." 
                    className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 text-slate-900 dark:text-white focus:border-indigo-600 outline-none transition-all shadow-sm font-bold"
                    value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}
                  />
                  <svg className="absolute left-4 top-4 text-slate-400" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 sm:pb-0 w-full scrollbar-hide">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat} onClick={() => setSelectedCategory(cat)}
                      className={`whitespace-nowrap px-6 py-3.5 rounded-2xl text-sm font-black transition-all ${selectedCategory === cat ? 'bg-indigo-600 text-white shadow-xl' : 'bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-400 border-2 border-slate-100 dark:border-slate-800 hover:border-indigo-300'}`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {filteredProducts.map(p => (
                <ProductCard key={p.id} product={p} onAdd={() => addToCart(p)} onClick={() => openProductDetail(p)} isAdmin={user?.isAdmin} onToggleFeatured={() => toggleFeatured(p.id)} />
              ))}
            </div>
          </div>
        )}

        {currentPage === 'cart' && (
          <div className="max-w-6xl mx-auto space-y-10 animate-in fade-in duration-500">
            <h1 className="text-4xl font-black text-slate-900 dark:text-white tracking-tighter">Your Bag</h1>
            {cart.length === 0 ? (
              <div className="bg-white dark:bg-slate-900 rounded-[3.5rem] p-24 text-center border-4 border-slate-50 dark:border-slate-800 shadow-2xl">
                <div className="text-indigo-100 dark:text-indigo-900/50 mb-8 flex justify-center">
                  <svg width="120" height="120" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><path d="M3 6h18"/><path d="M16 10a4 4 0 0 1-8 0"/></svg>
