                <h2 className="text-4xl font-black text-slate-900 dark:text-white">Your bag is empty!</h2>
                <p className="text-slate-500 dark:text-slate-400 mt-4 mb-10 text-xl font-bold">Time to explore our new Hair Care and Jewelry lines.</p>
                <button onClick={() => setCurrentPage('products')} className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black text-xl hover:bg-indigo-700 transition-all shadow-2xl">Browse Catalog</button>
              </div>
            ) : (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
                <div className="lg:col-span-2 space-y-6">
                  {cart.map(item => (
                    <div key={item.id} className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border-2 border-slate-50 dark:border-slate-800 flex gap-8 shadow-sm hover:shadow-xl transition-all">
                      <img src={item.image} alt={item.name} className="w-36 h-36 rounded-3xl object-cover shadow-lg" />
                      <div className="flex-1 flex flex-col justify-between">
                        <div className="flex justify-between items-start">
                          <div>
                            <h3 className="text-2xl font-black text-slate-900 dark:text-white leading-tight">{item.name}</h3>
                            <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 dark:bg-indigo-900/20 px-3 py-1 rounded-full uppercase tracking-widest">{item.category}</span>
                          </div>
                          <button onClick={() => removeFromCart(item.id)} className="p-3 text-slate-200 dark:text-slate-600 hover:text-red-500 bg-slate-50 dark:bg-slate-800 rounded-2xl transition-all">
