import { User, Order, CartItem, PaymentMethod, ContactMessage } from '../types';

const SIMULATE_DELAY = 1000;

class MockBackend {
  private users: User[] = [
    { id: '1', email: 'admin@susan.co.ke', name: 'Susan Admin', isAdmin: true },
    { id: '2', email: 'user@susan.co.ke', name: 'James Kariuki', isAdmin: false }
  ];

  private orders: Order[] = [];

  async login(email: string, password?: string): Promise<User> {
    await new Promise(r => setTimeout(r, SIMULATE_DELAY));
    let user = this.users.find(u => u.email === email);
    if (!user) {
      // Create a user on the fly for the demo, password is simulated
      user = { id: Math.random().toString(), email, name: email.split('@')[0], isAdmin: email.includes('admin') };
      this.users.push(user);
    }
    console.log('Backend: Logged in user', user.email);
    return user;
  }

  async placeOrder(userId: string, items: CartItem[], total: number, paymentMethod: PaymentMethod): Promise<Order> {
    await new Promise(r => setTimeout(r, SIMULATE_DELAY));
    const order: Order = {
      id: `ORD-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
      userId,
      items,
      total,
      paymentMethod,
      status: 'pending',
      createdAt: new Date().toISOString()
    };
    this.orders.push(order);
    console.log('Backend: Order Placed', order);
    return order;
  }

  async sendContactMessage(msg: ContactMessage): Promise<boolean> {
    await new Promise(r => setTimeout(r, SIMULATE_DELAY));
    console.log('Backend: Message Received from', msg.email, msg);
    return true;
  }
}

