  const [user, setUser] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('mpesa');
  const [checkoutStatus, setCheckoutStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [theme, setTheme] = useState<Theme>('light');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchTerm, products]);

  const featuredProducts = useMemo(() => products.filter(p => p.featured), [products]);

  const toggleFeatured = (id: string) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, featured: !p.featured } : p));
  };

  const handleAddProduct = (newProduct: Product) => {
    setProducts(prev => [newProduct, ...prev]);
    setCurrentPage('products');
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => setCart(prev => prev.filter(item => item.id !== id));

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const openProductDetail = (p: Product) => {
    setSelectedProduct(p);
    setCurrentPage('product-detail');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
  };

  const handleUpdateProfilePhoto = (photo: string) => {
    if (user) {
      setUser({ ...user, profilePhoto: photo });
    }
  };

  const totalCartPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartItemIds = cart.map(item => item.id);

  return (
    <div className="min-h-screen flex flex-col relative bg-slate-50 dark:bg-slate-950 transition-colors duration-500 overflow-x-hidden">
      {/* Background Image Texture */}
      <div className="fixed inset-0 pointer-events-none -z-10 overflow-hidden opacity-30 dark:opacity-10">
        <img 
          src="https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&q=80&w=2000" 
          alt="" 
          className="w-full h-full object-cover grayscale"
        />
      </div>

      <Navbar 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage} 
        cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
        user={user}
        onLogout={handleLogout}
        theme={theme}
        onToggleTheme={() => setTheme(theme === 'light' ? 'dark' : 'light')}
        onUpdateProfilePhoto={handleUpdateProfilePhoto}
      />

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8 sm:px-8">
        {currentPage === 'login' && <Login onLogin={(u) => { setUser(u); setCurrentPage('home'); }} onBack={() => setCurrentPage('home')} />}
        {currentPage === 'contact' && <Contact />}
        {currentPage === 'style-hub' && <StyleHub onAddToCart={addToCart} />}
        {currentPage === 'admin-panel' && <AdminPanel onAddProduct={handleAddProduct} />}
        {currentPage === 'affiliate' && <AffiliateProgram onAddToCart={addToCart} onViewDetail={openProductDetail} />}
        {currentPage === 'product-detail' && selectedProduct && (
          <ProductDetail 
            product={selectedProduct} 
            onAddToCart={addToCart} 
            onBack={() => setCurrentPage('products')} 
          />
        )}

        {currentPage === 'home' && (
          <div className="space-y-32 py-8 animate-in fade-in duration-700">
            {/* Hero Section */}
            <section className="relative h-[500px] sm:h-[750px] rounded-[4rem] overflow-hidden group shadow-[0_35px_60px_-15px_rgba(0,0,0,0.3)] border-8 border-white dark:border-slate-900 bg-indigo-950">
              <img 
                src="https://images.unsplash.com/photo-1441986300917-64674bd600d8?auto=format&fit=crop&q=80&w=2000" 
                alt="Luxury Shopping" 
                className="absolute inset-0 w-full h-full object-cover opacity-50 group-hover:scale-105 transition-transform duration-[2000ms]"
              />
              <div className="absolute inset-0 bg-gradient-to-tr from-indigo-950/90 via-indigo-950/40 to-transparent"></div>
              <div className="absolute inset-0 flex flex-col items-start justify-center p-12 sm:p-24 text-left">
                <span className="inline-flex items-center gap-2 bg-indigo-500/20 backdrop-blur-md text-indigo-200 text-[10px] font-black px-5 py-2 rounded-full uppercase tracking-[0.4em] mb-8 border border-white/10">
                  <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-ping"></span>
                  Nairobi Hub
                </span>
                <h1 className="text-6xl sm:text-[10rem] font-black text-white mb-8 leading-[0.85] tracking-tighter max-w-4xl">
                  Style <span className="text-indigo-400">Hub.</span><br/>
                  <span className="text-slate-400">Market</span>
                </h1>
                <p className="text-xl sm:text-3xl text-slate-300 max-w-xl mb-14 leading-relaxed font-semibold">
                  Curated hardware, tech, and high-fashion. Vetted by Susan Njeri, delivered locally.
                </p>
                <div className="flex flex-wrap gap-8">
                  <button onClick={() => setCurrentPage('products')} className="bg-white text-indigo-950 px-14 py-6 rounded-[2rem] font-black text-2xl hover:bg-indigo-50 hover:shadow-[0_0_50px_rgba(255,255,255,0.3)] transition-all active:scale-95 shadow-2xl">Start Shopping</button>
                  <button onClick={() => setCurrentPage('affiliate')} className="glass text-white px-14 py-6 rounded-[2rem] font-black text-2xl border-2 border-white/30 hover:bg-white/10 transition-all flex items-center gap-3">
                    Global Finds
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
                  </button>
                </div>
              </div>
            </section>

            {/* Meet Susan Njeri Section */}
            <section className="relative overflow-hidden py-12">
               <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[200%] aspect-square bg-indigo-600/5 dark:bg-indigo-600/10 rounded-full blur-[120px] -z-10"></div>
               <div className="max-w-7xl mx-auto flex flex-col lg:flex-row items-center gap-20 px-4">
                  <div className="w-full lg:w-1/2 relative">
                     <div className="relative z-10 group">
                        <div className="aspect-[3/4.5] rounded-[4rem] overflow-hidden border-8 border-white dark:border-slate-900 shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)] bg-slate-200">
                           <img 
                             src="https://iili.io/fyskfxj.jpg" 
                             alt="Susan Njeri" 
                             className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[1500ms]"
                             onError={(e) => {
                               (e.target as HTMLImageElement).src = 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?auto=format&fit=crop&q=80&w=800';
                             }}
                           />
                        </div>
                        <div className="absolute -bottom-10 -right-10 bg-white dark:bg-slate-800 p-8 rounded-[3rem] shadow-2xl border border-slate-100 dark:border-white/10 animate-bounce-slow">
                           <p className="text-4xl font-black text-indigo-600 tracking-tighter leading-none italic">S. Njeri</p>
                           <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2 text-center">Founder & CEO</p>
                        </div>
                     </div>
                  </div>
                  <div className="flex-1 space-y-10">
                     <span className="bg-amber-100 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 text-[10px] font-black px-6 py-2 rounded-full uppercase tracking-[0.3em] shadow-sm">The Visionary</span>
                     <h2 className="text-6xl sm:text-[6.5rem] font-black text-slate-900 dark:text-white tracking-tighter leading-[0.9]">
                        Meet <span className="text-indigo-600 underline decoration-8 decoration-indigo-600/20 underline-offset-8">Susan Njeri</span>.
                     </h2>
                     <div className="space-y-6">
                        <p className="text-2xl text-slate-600 dark:text-slate-300 font-bold leading-relaxed">
                          "I started Susan's Market to bring the highest quality hardware and lifestyle products directly to your doorstep in Kenya."
                        </p>
                        <p className="text-lg text-slate-500 dark:text-slate-400 font-medium italic">
                          "From smart home electronics to the finest industrial hardware, every piece is personally selected and vetted for excellence."
                        </p>
                     </div>
                     <div className="grid grid-cols-2 gap-8 pt-8 border-t border-slate-100 dark:border-white/5">
                        <div>
                           <p className="text-5xl font-black text-slate-900 dark:text-white tracking-tighter">15k+</p>
                           <p className="text-xs font-black text-slate-400 uppercase tracking-widest mt-1">Happy Clients</p>
                        </div>
                        <div>
                           <p className="text-5xl font-black text-slate-900 dark:text-white tracking-tighter">100%</p>
                           <p className="text-xs font-black text-slate-400 uppercase tracking-widest mt-1">Vetted Quality</p>
                        </div>
                     </div>
                  </div>
               </div>
            </section>

            {/* Featured Selection */}
            <section className="px-4">
              <div className="flex flex-col md:flex-row md:items-end justify-between mb-16 gap-6">
                <div>
                  <h2 className="text-5xl font-black text-slate-900 dark:text-white tracking-tighter">The Hot List</h2>
                  <p className="text-xl text-slate-500 dark:text-slate-400 mt-2 font-bold">Hand-picked bestsellers in hardware and tech.</p>
                </div>
                <button onClick={() => setCurrentPage('products')} className="group flex items-center gap-3 text-indigo-600 font-black uppercase text-xs tracking-widest hover:translate-x-2 transition-all">
                  See All Products
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
                </button>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-10">
                {featuredProducts.map(p => (
                  <ProductCard key={p.id} product={p} onAdd={() => addToCart(p)} onClick={() => openProductDetail(p)} isAdmin={user?.isAdmin} onToggleFeatured={() => toggleFeatured(p.id)} />
                ))}
              </div>
            </section>
          </div>
        )}

        {currentPage === 'products' && (
          <div className="space-y-16 py-8 animate-in fade-in duration-500">
            {/* Improved Header Alignment */}
            <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl p-8 sm:p-12 rounded-[3.5rem] shadow-xl border border-slate-50 dark:border-white/5 space-y-10">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-12">
                <div className="space-y-2">
                  <h1 className="text-5xl font-black text-slate-900 dark:text-white tracking-tighter">Marketplace</h1>
                  <div className="flex items-center gap-3">
                    <span className="w-10 h-1 bg-indigo-600 rounded-full"></span>
                    <p className="text-lg text-slate-500 dark:text-slate-400 font-bold">Kenya's curated high-end catalog.</p>
                  </div>
                </div>
                <div className="relative w-full md:w-96 group">
                  <input 
                    type="text" placeholder="Search brands, hardware, style..." 
                    className="w-full pl-14 pr-6 py-5 rounded-[2rem] border-2 border-slate-50 dark:border-slate-800 bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-white focus:border-indigo-600 focus:bg-white dark:focus:bg-slate-900 outline-none transition-all shadow-sm font-bold"
                    value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}
                  />
                  <svg className="absolute left-6 top-5 text-slate-400 group-focus-within:text-indigo-600 transition-colors" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                </div>
              </div>

              {/* Perfectly Centered & Sized Category Tabs */}
              <div className="flex justify-start md:justify-center overflow-x-auto pb-4 scrollbar-hide -mx-4 px-4 sm:mx-0 sm:px-0">
                <div className="flex gap-2 p-1.5 bg-slate-100 dark:bg-slate-800/50 rounded-[2.5rem] min-w-max">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat} onClick={() => setSelectedCategory(cat)}
                      className={`whitespace-nowrap px-8 py-3.5 rounded-[2rem] text-[10px] font-black uppercase tracking-[0.2em] transition-all duration-300 ${selectedCategory === cat ? 'bg-indigo-600 text-white shadow-xl scale-[1.05]' : 'text-slate-400 hover:text-slate-900 dark:hover:text-white hover:bg-white dark:hover:bg-slate-700'}`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-12">
              {filteredProducts.map(p => (
                <ProductCard key={p.id} product={p} onAdd={() => addToCart(p)} onClick={() => openProductDetail(p)} isAdmin={user?.isAdmin} onToggleFeatured={() => toggleFeatured(p.id)} />
              ))}
              {filteredProducts.length === 0 && (
                <div className="col-span-full py-32 text-center">
                  <div className="w-24 h-24 bg-slate-100 dark:bg-slate-800 rounded-[2.5rem] flex items-center justify-center text-slate-300 dark:text-slate-600 mx-auto mb-8">
                     <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 2v4"/><path d="m4.93 4.93 2.83 2.83"/><path d="M2 12h4"/><path d="m4.93 19.07 2.83-2.83"/><path d="M12 18v4"/><path d="m16.24 16.24 2.83 2.83"/><path d="M18 12h4"/><path d="m16.24 7.76 2.83-2.83"/></svg>
                  </div>
                  <p className="text-3xl font-black text-slate-400 dark:text-slate-600">No products match your current filters.</p>
                  <button onClick={() => { setSearchTerm(''); setSelectedCategory('All'); }} className="mt-8 px-12 py-5 bg-indigo-600 text-white rounded-[2rem] font-black uppercase text-xs tracking-[0.2em] shadow-xl hover:scale-105 active:scale-95 transition-all">Clear All Filters</button>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      <footer className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border-t border-slate-100 dark:border-white/5 mt-24 py-24 px-4 sm:px-8 transition-colors">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-16">
          <div className="col-span-1 md:col-span-2">
            <div className="flex items-center gap-4 mb-8">
              <div className="w-14 h-14 bg-indigo-600 rounded-[1.2rem] flex items-center justify-center text-white font-black text-3xl shadow-xl rotate-3">S</div>
              <span className="text-3xl font-black tracking-tighter text-slate-900 dark:text-white">Susan Njeri Market</span>
            </div>
            <p className="text-slate-500 dark:text-slate-400 max-w-sm mb-10 leading-relaxed font-bold text-lg">Kenya's premier destination for high-performance hardware, smart tech, and high-fashion curated with AI precision.</p>
          </div>
          <div>
            <h4 className="font-black text-slate-900 dark:text-white mb-8 uppercase text-xs tracking-[0.3em]">Marketplace</h4>
            <ul className="space-y-4 text-sm font-bold text-slate-400 dark:text-slate-500">
              <li><button onClick={() => { setCurrentPage('products'); setSelectedCategory('Electronics'); }} className="hover:text-indigo-600 transition-colors uppercase tracking-widest">Hardware & Tech</button></li>
              <li><button onClick={() => { setCurrentPage('products'); setSelectedCategory('Fashion'); }} className="hover:text-indigo-600 transition-colors uppercase tracking-widest">High Fashion</button></li>
              <li><button onClick={() => { setCurrentPage('products'); setSelectedCategory('Jewelry'); }} className="hover:text-indigo-600 transition-colors uppercase tracking-widest">Fine Jewelry</button></li>
              <li><button onClick={() => { setCurrentPage('affiliate'); }} className="hover:text-indigo-600 transition-colors uppercase tracking-widest">Global Sourcing</button></li>
            </ul>
          </div>
        </div>
        <div className="max-w-7xl mx-auto border-t border-slate-50 dark:border-slate-800 mt-20 pt-12 text-center text-[10px] text-slate-400 font-black uppercase tracking-[0.4em]">
          © {new Date().getFullYear()} Susan Njeri Marketplace. Handcrafted in Nairobi.
        </div>
      </footer>

      <Assistant cartItemIds={cartItemIds} />
    </div>
  );
};

