                <label className="block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 ml-1">Email</label>
                <input 
                  type="email" required
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  className="w-full px-5 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all" 
                  placeholder="juma@example.com"
                />
              </div>
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 ml-1">Subject</label>
              <input 
                type="text" required
                value={formData.subject}
                onChange={e => setFormData({...formData, subject: e.target.value})}
                className="w-full px-5 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all" 
                placeholder="Order Query"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 ml-1">Message</label>
              <textarea 
                required rows={4}
                value={formData.message}
                onChange={e => setFormData({...formData, message: e.target.value})}
                className="w-full px-5 py-3 rounded-2xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all resize-none" 
                placeholder="How can we help you?"
              />
            </div>
            <button 
              disabled={sending}
              type="submit"
              className="w-full bg-slate-900 dark:bg-indigo-600 text-white py-5 rounded-2xl font-black text-lg hover:bg-indigo-600 transition-all disabled:opacity-50 shadow-xl group flex items-center justify-center gap-3"
            >
              {sending ? (
                'Processing...'
              ) : (
                <>
                  Notify Susan via WhatsApp
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" className="group-hover:translate-x-1 transition-transform"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
                </>
              )}
            </button>
            <p className="text-center text-[10px] font-black text-slate-400 uppercase tracking-widest mt-4">
              Your inquiry will be sent to Susan's direct line.
            </p>
          </form>
        </div>
      </div>
      <style>{`
        @keyframes progress {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Product, CartItem, Page, User, PaymentMethod, Theme } from './types';
import { CATEGORIES } from './constants';
import { Navbar } from './components/Navbar';
import { Assistant } from './components/Assistant';
import { Login } from './components/Login';
import { Contact } from './components/Contact';
import { StyleHub } from './components/StyleHub';
import { ProductDetail } from './components/ProductDetail';
import { AdminPanel } from './components/AdminPanel';
import { AffiliateProgram } from './components/AffiliateProgram';
import { Cart } from './components/Cart';
import { backend } from './services/backendService';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('mpesa');
  const [checkoutStatus, setCheckoutStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [theme, setTheme] = useState<Theme>('light');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  // Load products from "Backend" on mount
  useEffect(() => {
    const fetchProducts = async () => {
      setIsLoading(true);
      const data = await backend.getProducts();
      setProducts(data);
      setIsLoading(false);
    };
    fetchProducts();
  }, []);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchTerm, products]);

  const featuredProducts = useMemo(() => products.filter(p => p.featured), [products]);

  const handleAddProduct = async (newProduct: Product) => {
    const added = await backend.addProduct(newProduct);
    setProducts(prev => [added, ...prev]);
    setCurrentPage('products');
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => setCart(prev => prev.filter(item => item.id !== id));

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleCheckout = async (method: PaymentMethod) => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    setCheckoutStatus('loading');
    await backend.placeOrder(user.id, cart, cart.reduce((a, b) => a + b.price * b.quantity, 0), method);
    setCheckoutStatus('success');
    setCart([]);
    alert(`Order Placed Successfully via ${method.toUpperCase()}!`);
    setCurrentPage('home');
    setCheckoutStatus('idle');
  };

  const openProductDetail = (p: Product) => {
    setSelectedProduct(p);
    setCurrentPage('product-detail');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
  };

  const handleUpdateProfilePhoto = (photo: string) => {
    if (user) {
      setUser({ ...user, profilePhoto: photo });
    }
  };

  const cartItemIds = cart.map(item => item.id);

  return (
    <div className="min-h-screen flex flex-col relative bg-slate-50 dark:bg-slate-950 transition-colors duration-500 overflow-x-hidden">

      {/* Dynamic Animated Background */}
      <div className="fixed inset-0 -z-10 pointer-events-none opacity-40 dark:opacity-20 transition-all">
        <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-indigo-200 dark:bg-indigo-900 rounded-full blur-[150px] animate-pulse"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-emerald-100 dark:bg-emerald-900 rounded-full blur-[150px] animate-pulse [animation-delay:2s]"></div>
      </div>

      <Navbar 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage} 
        cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
        user={user}
        onLogout={handleLogout}
        theme={theme}
        onToggleTheme={() => setTheme(theme === 'light' ? 'dark' : 'light')}
        onUpdateProfilePhoto={handleUpdateProfilePhoto}
      />

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8 sm:px-8">
        {isLoading && currentPage === 'products' ? (
          <div className="flex items-center justify-center py-40">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : (
          <>
            {currentPage === 'login' && <Login onLogin={(u) => { setUser(u); setCurrentPage('home'); }} onBack={() => setCurrentPage('home')} />}
            {currentPage === 'contact' && <Contact />}
            {currentPage === 'style-hub' && <StyleHub onAddToCart={addToCart} />}
            {currentPage === 'admin-panel' && <AdminPanel onAddProduct={handleAddProduct} />}
            {currentPage === 'affiliate' && <AffiliateProgram onAddToCart={addToCart} onViewDetail={openProductDetail} />}
            {currentPage === 'cart' && (
              <Cart 
                items={cart} 
                onRemove={removeFromCart} 
                onUpdateQuantity={updateQuantity} 
                onCheckout={handleCheckout} 
                onGoShopping={() => setCurrentPage('products')}
              />
            )}
            {currentPage === 'product-detail' && selectedProduct && (
              <ProductDetail 
