        {/* Subtle Tech Grid Pattern */}
        <div className="absolute inset-0 opacity-[0.03] dark:opacity-[0.05]" style={{ backgroundImage: `radial-gradient(#4f46e5 1px, transparent 1px)`, backgroundSize: '40px 40px' }}></div>

        {/* Floating Glass Shapes */}
        <div className="absolute top-40 left-1/4 w-32 h-32 glass rounded-[2rem] rotate-12 opacity-20 animate-[float_8s_ease-in-out_infinite]"></div>
        <div className="absolute bottom-40 right-1/4 w-24 h-24 glass rounded-full opacity-20 animate-[float_12s_ease-in-out_infinite] [animation-delay:2s]"></div>
        <div className="absolute top-1/3 right-10 w-16 h-16 glass rounded-[1rem] -rotate-45 opacity-20 animate-[float_10s_ease-in-out_infinite] [animation-delay:4s]"></div>
      </div>

      <Navbar 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage} 
        cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
        user={user}
        onLogout={handleLogout}
        theme={theme}
        onToggleTheme={() => setTheme(theme === 'light' ? 'dark' : 'light')}
        onUpdateProfilePhoto={handleUpdateProfilePhoto}
      />

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8 sm:px-8">
        {isLoading && currentPage === 'products' ? (
          <div className="flex items-center justify-center py-40">
