              </button>
              <button 
                onClick={() => setShowMpesaPrompt(false)}
                className="w-full text-slate-400 font-black text-xs uppercase tracking-widest py-2 hover:text-slate-900 dark:hover:text-white"
              >
                Cancel Transaction
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col lg:flex-row gap-16 items-start">
        <div className="flex-1 space-y-8 w-full">
          <div className="flex items-end justify-between border-b-4 border-slate-100 dark:border-white/5 pb-10">
            <h1 className="text-6xl font-black text-slate-900 dark:text-white tracking-tighter">Shopping Bag</h1>
            <span className="text-sm font-black text-slate-400 uppercase tracking-widest bg-slate-100 dark:bg-slate-800 px-6 py-2 rounded-full">{items.length} Items</span>
          </div>

          <div className="space-y-6">
            {items.map(item => (
              <div key={item.id} className="group bg-white dark:bg-slate-900 p-8 rounded-[3.5rem] border-2 border-slate-50 dark:border-white/5 flex flex-col sm:flex-row items-center gap-10 hover:shadow-2xl transition-all duration-500 relative overflow-hidden">
                <div className="w-40 h-40 rounded-[2.5rem] overflow-hidden bg-slate-100 flex-shrink-0 shadow-lg">
                  <img src={item.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={item.name} />
                </div>

                <div className="flex-1 space-y-2 text-center sm:text-left">
                  <h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight">{item.name}</h3>
                  <p className="text-sm font-bold text-slate-400 uppercase tracking-widest italic">{item.category}</p>
                  <p className="text-2xl font-black text-indigo-600 tracking-tighter">KES {item.price.toLocaleString()}</p>
                </div>

                <div className="flex items-center gap-6 bg-slate-50 dark:bg-slate-800 p-2 rounded-[2rem] border border-slate-100 dark:border-white/5">
                  <button onClick={() => onUpdateQuantity(item.id, -1)} className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white dark:bg-slate-700 text-slate-900 dark:text-white hover:bg-indigo-600 hover:text-white transition-all shadow-sm">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M5 12h14"/></svg>
                  </button>
                  <span className="text-xl font-black dark:text-white w-8 text-center">{item.quantity}</span>
                  <button onClick={() => onUpdateQuantity(item.id, 1)} className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white dark:bg-slate-700 text-slate-900 dark:text-white hover:bg-indigo-600 hover:text-white transition-all shadow-sm">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M5 12h14M12 5v14"/></svg>
                  </button>
                </div>

                <button onClick={() => onRemove(item.id)} className="p-4 text-slate-300 hover:text-red-500 transition-colors">
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M3 6h18M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
                </button>
              </div>
            ))}
          </div>
        </div>

        <div className="w-full lg:w-[450px] space-y-10 sticky top-40">
          <div className="bg-white dark:bg-slate-900 p-10 rounded-[4rem] border-2 border-slate-50 dark:border-white/5 shadow-2xl space-y-10">
            <h2 className="text-3xl font-black text-slate-900 dark:text-white tracking-tighter border-b-2 border-slate-50 dark:border-white/5 pb-6">Summary</h2>

            <div className="space-y-6">
              <div className="flex justify-between text-lg font-bold">
                <span className="text-slate-400">Subtotal</span>
                <span className="text-slate-900 dark:text-white font-black">KES {total.toLocaleString()}</span>
              </div>
              <div className="p-4 bg-amber-50 dark:bg-amber-950/20 rounded-3xl border border-amber-100 dark:border-amber-900/30 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-8 h-8 bg-amber-400 rounded-full flex items-center justify-center text-white shadow-sm">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
                  </div>
                  <span className="text-xs font-black text-amber-600 uppercase tracking-widest">Rewards</span>
                </div>
                <span className="text-lg font-black text-amber-600">+{potentialPoints} pts</span>
              </div>
              <div className="pt-6 border-t-2 border-slate-50 dark:border-white/5 flex justify-between items-center">
                <span className="text-2xl font-black text-slate-900 dark:text-white tracking-tighter">Total</span>
                <span className="text-4xl font-black text-indigo-600 tracking-tighter">KES {total.toLocaleString()}</span>
              </div>
            </div>

            <div className="space-y-6">
              <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-4">Payment Method</h3>
              <div className="grid grid-cols-2 gap-4">
                {[
                  { id: 'mpesa' as PaymentMethod, label: 'M-Pesa', color: 'bg-emerald-500' },
                  { id: 'visa' as PaymentMethod, label: 'Card', color: 'bg-indigo-600' }
                ].map(method => (
                  <button 
                    key={method.id}
                    onClick={() => setSelectedMethod(method.id)}
                    className={`p-6 rounded-3xl border-2 transition-all flex flex-col items-center gap-3 ${selectedMethod === method.id ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/10 shadow-lg' : 'border-slate-100 dark:border-white/5 bg-slate-50 dark:bg-slate-800 hover:border-indigo-200'}`}
                  >
                    <div className={`w-3 h-3 rounded-full ${method.color} ${selectedMethod === method.id ? 'animate-pulse' : ''}`}></div>
                    <span className="text-[10px] font-black uppercase tracking-widest dark:text-white">{method.label}</span>
                  </button>
                ))}
              </div>
            </div>

            <button 
              onClick={handleCheckout}
              disabled={isProcessing}
              className="w-full bg-slate-900 dark:bg-indigo-600 text-white py-8 rounded-[2.5rem] font-black text-2xl hover:bg-indigo-600 dark:hover:bg-indigo-700 transition-all shadow-2xl active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-4 overflow-hidden relative"
            >
              {isProcessing ? (
                <span className="flex items-center gap-4 animate-bounce">Processing...</span>
              ) : (
                <>
                  Checkout Now
                  <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
                </>
              )}
            </button>
            <p className="text-center text-[10px] font-black text-slate-400 uppercase tracking-widest leading-relaxed">
              Payments routed to: {SUSAN_CONTACT.PHONE}<br/>
              SSL Encrypted Transaction
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Product, CartItem, Page, User, PaymentMethod, Theme } from './types';
import { CATEGORIES } from './constants';
import { Navbar } from './components/Navbar';
import { Assistant } from './components/Assistant';
import { Login } from './components/Login';
import { Contact } from './components/Contact';
import { StyleHub } from './components/StyleHub';
import { ProductDetail } from './components/ProductDetail';
import { AdminPanel } from './components/AdminPanel';
import { AffiliateProgram } from './components/AffiliateProgram';
import { Cart } from './components/Cart';
import { backend } from './services/backendService';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  useEffect(() => {
    const fetchProducts = async () => {
      setIsLoading(true);
      const data = await backend.getProducts();
      setProducts(data);
      setIsLoading(false);
    };
    fetchProducts();
  }, []);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchTerm, products]);

  const featuredProducts = useMemo(() => products.filter(p => p.featured), [products]);

  const handleAddProduct = async (newProduct: Product) => {
    const added = await backend.addProduct(newProduct);
    setProducts(prev => [added, ...prev]);
    setCurrentPage('products');
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => setCart(prev => prev.filter(item => item.id !== id));

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleCheckout = async (method: PaymentMethod) => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    const total = cart.reduce((a, b) => a + b.price * b.quantity, 0);
    await backend.placeOrder(user.id, cart, total, method);

    // Refresh user to update points
    const updatedUser = await backend.login(user.email);
    setUser(updatedUser);

    setCart([]);
    alert(`Success! Payment of KES ${total.toLocaleString()} received via ${method.toUpperCase()}. You earned ${Math.floor(total * 0.01)} loyalty points!`);
    setCurrentPage('home');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const openProductDetail = (p: Product) => {
    setSelectedProduct(p);
    setCurrentPage('product-detail');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogout = () => {
    setUser(null);
    setCurrentPage('home');
  };

  const handleUpdateProfilePhoto = (photo: string) => {
    if (user) {
      setUser({ ...user, profilePhoto: photo });
    }
  };

  const cartItemIds = cart.map(item => item.id);

  return (
    <div className="min-h-screen flex flex-col relative bg-slate-50 dark:bg-slate-950 transition-colors duration-500 overflow-x-hidden">

      {/* High-End Dynamic Background Features */}
      <div className="fixed inset-0 -z-10 pointer-events-none transition-all">
        {/* Pulsing Core Blobs */}
        <div className="absolute top-[-10%] left-[-10%] w-[65%] h-[65%] bg-indigo-500/10 dark:bg-indigo-600/10 rounded-full blur-[180px] animate-[pulse_12s_ease-in-out_infinite]"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[65%] h-[65%] bg-emerald-400/10 dark:bg-emerald-500/10 rounded-full blur-[180px] animate-[pulse_18s_ease-in-out_infinite] [animation-delay:4s]"></div>

        {/* Parallax Floating Particles */}
        <div className="absolute top-[20%] left-[15%] w-1.5 h-1.5 bg-indigo-600 rounded-full animate-ping [animation-duration:3s]"></div>
        <div className="absolute bottom-[30%] right-[25%] w-2 h-2 bg-emerald-500 rounded-full animate-ping [animation-duration:4s]"></div>
        <div className="absolute top-1/2 left-[80%] w-1 h-1 bg-amber-500 rounded-full animate-ping [animation-duration:5s]"></div>

        {/* Dynamic Tech Grid Pattern */}
        <div 
          className="absolute inset-0 opacity-[0.04] dark:opacity-[0.08]" 
          style={{ backgroundImage: `linear-gradient(to right, #4f46e5 1px, transparent 1px), linear-gradient(to bottom, #4f46e5 1px, transparent 1px)`, backgroundSize: '60px 60px' }}
        ></div>

        {/* Floating Glass Panels */}
        <div className="absolute top-24 left-[10%] w-48 h-48 glass rounded-[3.5rem] rotate-12 opacity-10 animate-[float_10s_ease-in-out_infinite]"></div>
        <div className="absolute bottom-32 right-[15%] w-40 h-40 glass rounded-full opacity-10 animate-[float_15s_ease-in-out_infinite] [animation-delay:2s]"></div>
      </div>

      <Navbar 
        currentPage={currentPage} 
        setCurrentPage={setCurrentPage} 
        cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
        user={user}
        onLogout={handleLogout}
        theme={theme}
        onToggleTheme={() => setTheme(theme === 'light' ? 'dark' : 'light')}
        onUpdateProfilePhoto={handleUpdateProfilePhoto}
      />

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-8 sm:px-8">
        {isLoading && currentPage === 'products' ? (
          <div className="flex flex-col items-center justify-center py-60 space-y-8">
            <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-sm font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">Syncing Susan's Catalog...</p>
          </div>
        ) : (
          <>
            {currentPage === 'login' && <Login onLogin={(u) => { setUser(u); setCurrentPage('home'); }} onBack={() => setCurrentPage('home')} />}
            {currentPage === 'contact' && <Contact />}
            {currentPage === 'style-hub' && <StyleHub onAddToCart={addToCart} />}
            {currentPage === 'admin-panel' && <AdminPanel onAddProduct={handleAddProduct} />}
            {currentPage === 'affiliate' && <AffiliateProgram onAddToCart={addToCart} onViewDetail={openProductDetail} />}
            {currentPage === 'cart' && (
              <Cart items={cart} onRemove={removeFromCart} onUpdateQuantity={updateQuantity} onCheckout={handleCheckout} onGoShopping={() => setCurrentPage('products')} />
            )}
            {currentPage === 'product-detail' && selectedProduct && (
              <ProductDetail product={selectedProduct} onAddToCart={addToCart} onBack={() => setCurrentPage('products')} />
            )}

            {currentPage === 'home' && (
              <div className="space-y-32 py-8 animate-in fade-in duration-1000">
                {/* Hero Section */}
                <section className="relative h-[600px] sm:h-[800px] rounded-[4rem] overflow-hidden group shadow-2xl border-8 border-white dark:border-slate-900 bg-slate-900">
                  <img src="https://images.unsplash.com/photo-1441986300917-64674bd600d8?auto=format&fit=crop&q=80&w=2000" alt="Hero" className="absolute inset-0 w-full h-full object-cover opacity-60 group-hover:scale-105 transition-transform duration-[4000ms]" />
                  <div className="absolute inset-0 bg-gradient-to-tr from-slate-950 via-slate-900/30 to-transparent"></div>
                  <div className="absolute inset-0 flex flex-col items-start justify-center p-12 sm:p-24">
                    <span className="inline-flex items-center gap-2 bg-white/10 backdrop-blur-md text-white text-[10px] font-black px-6 py-2.5 rounded-full uppercase tracking-[0.4em] mb-10 border border-white/20">
                      <span className="w-2 h-2 bg-white rounded-full animate-ping"></span>
                      Now with Rewards
                    </span>
                    <h1 className="text-7xl sm:text-[11rem] font-black text-white mb-10 leading-[0.8] tracking-tighter max-w-5xl">
                      Style <span className="text-indigo-400">Earns.</span><br/>
                      <span className="text-slate-400">Rewards.</span>
                    </h1>
                    <p className="text-2xl sm:text-4xl text-slate-300 max-w-2xl mb-16 leading-relaxed font-bold">
                      Shop Nairobi's finest hardware and tech. Earn points on every KES spent.
                    </p>
                    <div className="flex flex-wrap gap-10">
                      <button onClick={() => setCurrentPage('products')} className="bg-white text-indigo-950 px-16 py-7 rounded-[2.5rem] font-black text-2xl hover:bg-indigo-50 hover:shadow-2xl transition-all active:scale-95">Explore Shop</button>
                      <button onClick={() => setCurrentPage('style-hub')} className="glass text-white px-16 py-7 rounded-[2.5rem] font-black text-2xl border-2 border-white/40 hover:bg-white/10 transition-all flex items-center gap-4">
                        AI Stylist Nova
                        <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 2v4"/><path d="M12 18v4"/><path d="M4.93 4.93l2.83 2.83"/><path d="M16.24 16.24l2.83 2.83"/><path d="M2 12h4"/><path d="M18 12h4"/><path d="M4.93 19.07l2.83-2.83"/><path d="M16.24 7.76l2.83-2.83"/></svg>
                      </button>
                    </div>
                  </div>
                </section>

                {/* Featured Products */}
                <section className="px-4">
                  <div className="flex items-end justify-between mb-20">
                    <div>
                      <h2 className="text-6xl font-black text-slate-900 dark:text-white tracking-tighter">Market Hotlist</h2>
                      <p className="text-2xl text-slate-500 dark:text-slate-400 mt-3 font-bold">Vetted by Susan Njeri.</p>
                    </div>
                    <button onClick={() => setCurrentPage('products')} className="group flex items-center gap-4 text-indigo-600 font-black uppercase text-sm tracking-widest hover:translate-x-3 transition-all">
                      Browse Full Catalog
                      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
                    </button>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-12">
                    {featuredProducts.map(p => (
                      <ProductCard key={p.id} product={p} onAdd={() => addToCart(p)} onClick={() => openProductDetail(p)} />
                    ))}
                  </div>
                </section>
              </div>
            )}

            {currentPage === 'products' && (
              <div className="space-y-16 py-8 animate-in fade-in duration-500">
                <div className="sticky top-24 z-30 bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl p-8 sm:p-12 rounded-[3.5rem] shadow-xl border border-white/20 dark:border-white/5 space-y-10">
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-12">
                    <div className="space-y-2">
                      <h1 className="text-6xl font-black text-slate-900 dark:text-white tracking-tighter">Marketplace</h1>
                      <p className="text-xl text-slate-500 dark:text-slate-400 font-bold">Curated global hardware for Nairobi.</p>
                    </div>
                    <div className="relative w-full md:w-[450px] group">
                      <input 
                        type="text" placeholder="Search brands, hardware, style..." 
                        className="w-full pl-16 pr-8 py-6 rounded-[2.5rem] border-2 border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-white focus:border-indigo-600 focus:bg-white dark:focus:bg-slate-900 outline-none transition-all shadow-sm font-bold text-lg"
                        value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}
                      />
                      <svg className="absolute left-6 top-6 text-slate-400 group-focus-within:text-indigo-600 transition-colors" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                    </div>
                  </div>
                  <div className="flex justify-start md:justify-center overflow-x-auto pb-4 scrollbar-hide -mx-4 px-4">
                    <div className="flex gap-3 p-2 bg-slate-100 dark:bg-slate-800/50 rounded-[3rem] min-w-max border border-white/10">
                      {CATEGORIES.map(cat => (
                        <button key={cat} onClick={() => setSelectedCategory(cat)} className={`whitespace-nowrap px-10 py-4 rounded-[2.5rem] text-[11px] font-black uppercase tracking-[0.25em] transition-all duration-300 ${selectedCategory === cat ? 'bg-indigo-600 text-white shadow-xl scale-[1.05]' : 'text-slate-400 hover:text-slate-900 dark:hover:text-white hover:bg-white dark:hover:bg-slate-700'}`}>{cat}</button>
                      ))}
                    </div>
                  </div>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-12">
                  {filteredProducts.map(p => (
                    <ProductCard key={p.id} product={p} onAdd={() => addToCart(p)} onClick={() => openProductDetail(p)} />
                  ))}
                </div>
              </div>
            )}
          </>
        )}
      </main>

      <footer className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl border-t border-slate-100 dark:border-white/5 mt-24 py-24 px-4 sm:px-8">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-20">
          <div className="col-span-1 md:col-span-2">
            <div className="flex items-center gap-5 mb-10">
              <div className="w-16 h-16 bg-indigo-600 rounded-[1.4rem] flex items-center justify-center text-white font-black text-4xl shadow-xl rotate-3">S</div>
              <span className="text-4xl font-black tracking-tighter text-slate-900 dark:text-white leading-none">Susan's Market</span>
