export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Product, GroundingSource } from "../types";
import { PRODUCTS } from "../constants";

// Strictly follow the rule: Use process.env.API_KEY directly in the constructor.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getShoppingAssistantResponse = async (userQuery: string, cartItems: string[]) => {
  const model = "gemini-3-flash-preview";

  const productContext = PRODUCTS.map(p => 
    `ID: ${p.id}, Name: ${p.name}, Category: ${p.category}, Price: KES ${p.price}, Description: ${p.description}`
  ).join("\n");

  const systemInstruction = `
    You are Nova, the high-end Personal Shopping Assistant for Susan's Market. 
    Our catalog features elite hardware, premium fashion, and curated lifestyle products.

    Current Catalog context:
    ${productContext}

    User's Current Cart IDs: [${cartItems.join(", ")}]

    Your Persona:
    - Sophisticated, helpful, and knowledgeable about luxury trends and hardware specs.
    - Always recommend items specifically from our current catalog using their names and prices.
    - Use the Google Search tool for real-time market trends, tech specs, or comparing our prices with global standards.
    - If you find external info via search, mention it but prioritize our shop's availability.
    - Remind users we accept M-Pesa, PayPal, and Cards.
    - Keep answers concise, formatted for high readability.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: userQuery,
      config: {
        systemInstruction,
        temperature: 0.7,
        tools: [{ googleSearch: {} }],
        thinkingConfig: { thinkingBudget: 0 }
      },
    });

    const sources: GroundingSource[] = [];
    const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
    const chunks = groundingMetadata?.groundingChunks;

    if (chunks && Array.isArray(chunks)) {
      chunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({
            title: chunk.web.title,
            uri: chunk.web.uri
          });
        }
      });
    }

    return {
      text: response.text || "I'm sorry, I couldn't process that request right now.",
      sources: sources.length > 0 ? sources : undefined
    };
  } catch (error: any) {
    console.error("Gemini Assistant Error Details:", error);
    // Provide a more helpful error for development/deployment debugging without leaking secrets
    return {
      text: `My apologies. I encountered an issue: ${error?.message || "Internal Service Error"}. Please ensure your API deployment has a valid KES Project key configured.`
    };
  }
};

export const getStyleHubRecommendations = async (styleDescription: string) => {
  const model = "gemini-3-flash-preview";

  const productContext = PRODUCTS.map(p => ({
    id: p.id,
    name: p.name,
    category: p.category,
    desc: p.description
  }));

  const systemInstruction = `
    You are the Style Consultant for Susan's Market.
    Analyze the user's vibe and return exactly 4 product IDs from our catalog that best match their description.

    Catalog: ${JSON.stringify(productContext)}

    Output ONLY a raw JSON array of the 4 most relevant product IDs.
    No other text. Example: ["id1", "id2", "id3", "id4"]
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: styleDescription,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 }
      },
    });

    const text = response.text || "[]";
    const jsonStr = text.replace(/```json/g, '').replace(/```/g, '').trim();
    const ids = JSON.parse(jsonStr);
    return PRODUCTS.filter(p => ids.includes(p.id));
  } catch (error) {
    console.error("Style Hub AI Error:", error);
    return [];
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Product, CartItem, Page, User, PaymentMethod, Theme } from './types';
import { CATEGORIES } from './constants';
import { Navbar } from './components/Navbar';
import { Assistant } from './components/Assistant';
import { Login } from './components/Login';
import { Contact } from './components/Contact';
import { StyleHub } from './components/StyleHub';
import { ProductDetail } from './components/ProductDetail';
import { AdminPanel } from './components/AdminPanel';
import { AffiliateProgram } from './components/AffiliateProgram';
import { Cart } from './components/Cart';
import { backend } from './services/backendService';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [user, setUser] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [theme, setTheme] = useState<Theme>('light');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Persistence: Restore user session and theme on mount
  useEffect(() => {
    const savedUser = localStorage.getItem('susan_market_active_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }

    const savedTheme = localStorage.getItem('susan_market_theme') as Theme;
    if (savedTheme) {
      setTheme(savedTheme);
    }
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('susan_market_theme', theme);
  }, [theme]);

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        setIsLoading(true);
        const data = await backend.getProducts();
        setProducts(data);
      } catch (err) {
        console.error("Failed to fetch products:", err);
      } finally {
        setIsLoading(false);
      }
    };
    fetchProducts();
  }, []);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.category === selectedCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          p.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchTerm, products]);

  const featuredProducts = useMemo(() => products.filter(p => p.featured), [products]);

  const handleAddProduct = async (newProduct: Product) => {
    const added = await backend.addProduct(newProduct);
    setProducts(prev => [added, ...prev]);
    setCurrentPage('products');
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => setCart(prev => prev.filter(item => item.id !== id));

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleCheckout = async (method: PaymentMethod) => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    const total = cart.reduce((a, b) => a + b.price * b.quantity, 0);
    await backend.placeOrder(user.id, cart, total, method);

    const updatedUser = await backend.login(user.email);
    setUser(updatedUser);
    localStorage.setItem('susan_market_active_user', JSON.stringify(updatedUser));

    setCart([]);
    alert(`Success! Payment of KES ${total.toLocaleString()} received via ${method.toUpperCase()}. You earned ${Math.floor(total * 0.01)} loyalty points!`);
    setCurrentPage('home');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const openProductDetail = (p: Product) => {
    setSelectedProduct(p);
    setCurrentPage('product-detail');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLoginSuccess = (u: User) => {
    setUser(u);
    localStorage.setItem('susan_market_active_user', JSON.stringify(u));
    setCurrentPage('home');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('susan_market_active_user');
    setCurrentPage('home');
  };

  const handleUpdateProfilePhoto = (photo: string) => {
    if (user) {
      const updatedUser = { ...user, profilePhoto: photo };
      setUser(updatedUser);
      localStorage.setItem('susan_market_active_user', JSON.stringify(updatedUser));
    }
  };

  const cartItemIds = cart.map(item => item.id);

  return (
    <div className="min-h-screen flex flex-col relative bg-slate-50 dark:bg-slate-950 transition-colors duration-500 overflow-x-hidden">

